def count_vowels_words(s):
    vowels = 'aeiouAEIOU'
    vc = 0
    for c in s:
        if c in vowels:
            vc += 1
    words = 0
    inword = False
    for c in s:
        if c == ' ':
            inword = False
        else:
            if not inword:
                words += 1
            inword = True
    return (vc, words)
