def is_anagram(a, b):
    if len(a) != len(b):
        return False
    f = {}
    for c in a:
        f[c] = f.get(c, 0) + 1
    for c in b:
        if f.get(c, 0) == 0:
            return False
        f[c] -= 1
    return True
```

