def selection_sort(a):
    a = a[:]
    n = len(a)
    for i in range(n):
        mi = i
        for j in range(i + 1, n):
            if a[j] < a[mi]:
                mi = j
        a[i], a[mi] = a[mi], a[i]
    return a
```

