def quicksort(a):
    if len(a) <= 1:
        return a[:]
    pivot = a[len(a) // 2]
    less = [x for x in a if x < pivot]
    eq = [x for x in a if x == pivot]
    gr = [x for x in a if x > pivot]
    return quicksort(less) + eq + quicksort(gr)
```

